code.C:
#include <stdio.h>
#define MOD 1000000007
int countDigits(long long n) {
    int count = 0;
    while (n != 0) {
        n /= 10;
        count++;
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long sum = 0;
        for (long long i = L; i <= R; i++) {
            sum = (sum + i * countDigits(i)) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

