code.Java:
import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static int countDigits(long n) {
        int count = 0;
        while (n != 0) {
            n /= 10;
            count++;
        }
        return count;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long L = sc.nextLong();
            long R = sc.nextLong();
            long sum = 0;
            for (long i = L; i <= R; i++) {
                sum = (sum + i * countDigits(i)) % MOD;
            }
            System.out.println(sum);
        }
    }
}

