const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
const lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let l = 0;
    const MOD = 1000000007;
    function countDigits(n) {
        let count = 0;
        while (n != 0) {
            n = Math.floor(n / 10);
            count++;
        }
        return count;
    }
    const T = parseInt(lines[l++]);
    for (let i = 0; i < T; i++) {
        const [L, R] = lines[l++].split(' ').map(Number);
        let sum = 0;
        for (let j = L; j <= R; j++) {
            sum = (sum + j * countDigits(j)) % MOD;
        }
        console.log(sum);
    }
});

